from lxml import etree

def process_soap_request(xml_request):
    """
    Processes SOAP XML requests from client applications.

    Args:
        xml_request: The SOAP XML request string.

    Returns:
        The message body of the SOAP request.
    """

    # Parse the SOAP request with DTD validation
    root = etree.fromstring(xml_request.encode('utf-8'), etree.DTD(etree.parse('soap.dtd')))

    # Extract the message body
    message_body = root.find('.//soapenv:Body').text

    return message_body